## for_each e count

### count

```hcl
variable "subnets" {
  default = [
    { name = "web", cidr = "10.0.1.0/24" },
    { name = "app", cidr = "10.0.2.0/24" },
    { name = "db",  cidr = "10.0.3.0/24" }
  ]
}

resource "oci_core_subnet" "subnets" {
  count          = length(var.subnets)
  compartment_id = var.compartment_id
  vcn_id         = oci_core_vcn.vcn.id
  cidr_block     = var.subnets[count.index].cidr
  display_name   = var.subnets[count.index].name
}
```

### for_each

```hcl
variable "users" {
  default = {
    "alice" = { email = "alice@example.com", group = "admins" },
    "bob"   = { email = "bob@example.com", group = "developers" }
  }
}

resource "oci_identity_user" "users" {
  for_each = var.users
  name     = each.key
  email    = each.value.email
}
```

